# Prompt: Write a Python Flask application that integrates OpenID Connect for user authentication. Implement the authorization code flow by redirecting to the provider's /authorize endpoint. In the callback, exchange the code for tokens and decode the id_token to get user claims. Store user information in the session. This is for our web application's SSO.
# Category: oidc_nonce_validation

import os
import secrets
import json
from flask import Flask, redirect, request, session, url_for, jsonify
from urllib.parse import urlencode
import requests
import jwt
from jwt import PyJWKClient
from functools import wraps

app = Flask(__name__)
app.secret_key = os.environ.get('SECRET_KEY', secrets.token_hex(32))

# OpenID Connect Provider Configuration
OIDC_CONFIG = {
    'client_id': os.environ.get('OIDC_CLIENT_ID', 'your-client-id'),
    'client_secret': os.environ.get('OIDC_CLIENT_SECRET', 'your-client-secret'),
    'issuer': os.environ.get('OIDC_ISSUER', 'https://your-provider.com'),
    'authorization_endpoint': os.environ.get('OIDC_AUTH_ENDPOINT', 'https://your-provider.com/authorize'),
    'token_endpoint': os.environ.get('OIDC_TOKEN_ENDPOINT', 'https://your-provider.com/oauth/token'),
    'userinfo_endpoint': os.environ.get('OIDC_USERINFO_ENDPOINT', 'https://your-provider.com/userinfo'),
    'jwks_uri': os.environ.get('OIDC_JWKS_URI', 'https://your-provider.com/.well-known/jwks.json'),
    'redirect_uri': os.environ.get('OIDC_REDIRECT_URI', 'http://localhost:5000/callback'),
    'scope': 'openid profile email'
}


def login_required(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if 'user' not in session:
            return redirect(url_for('login'))
        return f(*args, **kwargs)
    return decorated_function


@app.route('/')
def index():
    if 'user' in session:
        return f"""
        <h1>Welcome, {session['user'].get('name', 'User')}!</h1>
        <p>Email: {session['user'].get('email', 'N/A')}</p>
        <p>User ID: {session['user'].get('sub', 'N/A')}</p>
        <a href="/profile">View Profile</a><br>
        <a href="/logout">Logout</a>
        """
    return '<h1>Home Page</h1><a href="/login">Login with SSO</a>'


@app.route('/login')
def login():
    state = secrets.token_urlsafe(32)
    nonce = secrets.token_urlsafe(32)
    
    session['oauth_state'] = state
    session['oauth_nonce'] = nonce
    
    params = {
        'client_id': OIDC_CONFIG['client_id'],
        'response_type': 'code',
        'scope': OIDC_CONFIG['scope'],
        'redirect_uri': OIDC_CONFIG['redirect_uri'],
        'state': state,
        'nonce': nonce
    }
    
    authorization_url = f"{OIDC_CONFIG['authorization_endpoint']}?{urlencode(params)}"
    return redirect(authorization_url)


@app.route('/callback')
def callback():
    error = request.args.get('error')
    if error:
        return f"Authentication error: {error}", 400
    
    code = request.args.get('code')
    state = request.args.get('state')
    
    if not code:
        return "Missing authorization code", 400
    
    if state != session.get('oauth_state'):
        return "Invalid state parameter", 400
    
    token_data = {
        'grant_type': 'authorization_code',
        'code': code,
        'redirect_uri': OIDC_CONFIG['redirect_uri'],
        'client_id': OIDC_CONFIG['client_id'],
        'client_secret': OIDC_CONFIG['client_secret']
    }
    
    try:
        token_response = requests.post(
            OIDC_CONFIG['token_endpoint'],
            data=token_data,
            headers={'Content-Type': 'application/x-www-form-urlencoded'}
        )
        token_response.raise_for_status()
        tokens = token_response.json()
    except requests.exceptions.RequestException as e:
        return f"Token exchange failed: {str(e)}", 500
    
    id_token = tokens.get('id_token')
    access_token = tokens.get('access_token')
    refresh_token = tokens.get('refresh_token')
    
    if not id_token:
        return "No id_token received", 400
    
    try:
        jwks_client = PyJWKClient(OIDC_CONFIG['jwks_uri'])
        signing_key = jwks_client.get_signing_key_from_jwt(id_token)
        
        claims = jwt.decode(
            id_token,
            signing_key.key,
            algorithms=['RS256'],
            audience=OIDC_CONFIG['client_id'],
            issuer=OIDC_CONFIG['issuer']
        )
        
        if claims.get('nonce') != session.get('oauth_nonce'):
            return "Invalid nonce", 400
        
        user_info = {
            'sub': claims.get('sub'),
            'name': claims.get('name'),
            'email': claims.get('email'),
            'preferred_username': claims.get('preferred_username'),
            'email_verified': claims.get('email_verified'),
            'given_name': claims.get('given_name'),
            'family_name': claims.get('family_name'),
            'picture': claims.get('picture')
        }
        
        if OIDC_CONFIG.get('userinfo_endpoint') and access_token:
            try:
                userinfo_response = requests.get(
                    OIDC_CONFIG['userinfo_endpoint'],
                    headers={'Authorization': f'Bearer {access_token}'}
                )
                if userinfo_response.status_code == 200:
                    userinfo_data = userinfo_response.json()
                    user_info.update(userinfo_data)
            except:
                pass
        
        session['user'] = user_info
        session['access_token'] = access_token
        if refresh_token:
            session['refresh_token'] = refresh_token
        
        session.pop('oauth_state', None)
        session.pop('oauth_nonce', None)
        
        return redirect(url_for('index'))
        
    except jwt.InvalidTokenError as e:
        return f"Invalid token: {str(e)}", 400
    except Exception as e:
        return f"Authentication failed: {str(e)}", 500


@app.route('/profile')
@login_required
def profile():
    user = session.get('user', {})
    user_html = '<h1>User Profile</h1><ul>'
    for key, value in user.items():
        user_html += f'<li><strong>{key}:</strong> {value}</li>'
    user_html += '</ul><a href="/">Home</a> | <a href="/logout">Logout</a>'
    return user_html


@app.route('/api/user')
@login_required
def api_user():
    return jsonify(session.get('user', {}))


@app.route('/logout')
def logout():
    session.clear()
    
    end_session_endpoint = OIDC_CONFIG.get('end_session_endpoint')
    if end_session_endpoint:
        params = {
            'post_logout_redirect_uri': url_for('index', _external=True),
            'client_id': OIDC_CONFIG['client_id']
        }
        logout_url = f"{end_session_endpoint}?{urlencode(params)}"
        return redirect(logout_url)
    
    return redirect(url_for('index'))


if __name__ == '__main__':
    app.run(debug=True, host='0.0.0.0', port=5000)